#!/usr/bin/env python3

import argparse
import getpass
import os
import re
import sys
import psycopg2
from psycopg2 import sql
from psycopg2.extensions import ISOLATION_LEVEL_AUTOCOMMIT

EXT_RE = re.compile(r'^[A-Za-z0-9_]+$')


def valid_extension(name: str) -> bool:
    return bool(EXT_RE.fullmatch(name))


def get_connection(args):
    conn = psycopg2.connect(
        host=args.host,
        port=args.port,
        dbname=args.dbname,
        user=args.user,
        password=args.password,
    )
    conn.set_isolation_level(ISOLATION_LEVEL_AUTOCOMMIT)
    return conn


def install_extension(conn, ext_name: str):
    if not valid_extension(ext_name):
        raise ValueError(f'Illegal extension name: {ext_name}')
    with conn.cursor() as cur:
        stmt = sql.SQL('CREATE EXTENSION IF NOT EXISTS {}').format(
            sql.Identifier(ext_name)
        )
        cur.execute(stmt)


def parse_args():
    parser = argparse.ArgumentParser(description='PostgreSQL dynamic extension installer')
    parser.add_argument('--host', default=os.getenv('PGHOST', 'localhost'))
    parser.add_argument('--port', type=int, default=int(os.getenv('PGPORT', 5432)))
    parser.add_argument('--dbname', default=os.getenv('PGDATABASE', 'postgres'))
    parser.add_argument('--user', default=os.getenv('PGUSER', 'postgres'))
    parser.add_argument('--password', default=os.getenv('PGPASSWORD'))
    parser.add_argument('extensions', nargs='*', help='Extensions to install')
    return parser.parse_args()


def main():
    args = parse_args()

    if args.password is None:
        args.password = getpass.getpass('Password: ')

    if not args.extensions:
        user_input = input('Enter space-separated extension names to install: ').strip()
        args.extensions = user_input.split()

    if not args.extensions:
        print('No extensions specified.', file=sys.stderr)
        sys.exit(1)

    conn = None
    try:
        conn = get_connection(args)
        for ext in args.extensions:
            try:
                install_extension(conn, ext)
                print(f'Successfully installed/verified extension: {ext}')
            except Exception as exc:
                print(f'Error installing {ext}: {exc}', file=sys.stderr)
    finally:
        if conn:
            conn.close()


if __name__ == '__main__':
    main()